css:
/* Main container */
.leave-request-format {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    max-width: 210mm;
    margin: 0 auto;
    padding: 20mm;
    background: #fff;
    color: #333;
    line-height: 1.6;
}

/* Header styling */
.header {
    text-align: center;
    margin-bottom: 30px;
}

.header h2 {
    font-size: 28px;
    font-weight: bold;
    color: #2c3e50;
    margin: 0 0 15px 0;
    text-transform: uppercase;
    letter-spacing: 2px;
}

.company-info p {
    font-size: 14px;
    margin: 5px 0;
    color: #7f8c8d;
}

/* Section breaks with border except last */
.section-break {
    padding: 20px 0;
    border-bottom: 2px solid #ecf0f1;
}

.section-break:last-child {
    padding-bottom: 0;
    border-bottom: none;
}

.section-break h3 {
    font-size: 16px;
    font-weight: bold;
    color: #34495e;
    margin: 0 0 15px 0;
    text-transform: uppercase;
    border-left: 4px solid #3498db;
    padding-left: 10px;
}

/* Field groups styling */
.field-group {
    display: flex;
    margin-bottom: 12px;
    align-items: flex-start;
}

.field-group .label {
    min-width: 150px;
    font-weight: 600;
    color: #2c3e50;
    margin-right: 15px;
    flex-shrink: 0;
}

.field-group .value {
    flex: 1;
    color: #34495e;
    word-wrap: break-word;
}

/* Specific field type styling based on data attributes */
[data-fieldtype="Date"] .value {
    font-weight: 600;
    color: #27ae60;
}

[data-fieldtype="Link"] .value {
    color: #3498db;
    font-weight: 500;
}

[data-fieldtype="Select"] .value {
    text-transform: uppercase;
    font-weight: bold;
    padding: 3px 8px;
    border-radius: 3px;
}

[data-fieldtype="Text"] .value {
    font-style: italic;
    background-color: #f8f9fa;
    padding: 8px;
    border-left: 3px solid #dee2e6;
    border-radius: 3px;
}

/* Priority-specific styling */
.priority-high {
    background-color: #e74c3c;
    color: white;
}

.priority-medium {
    background-color: #f39c12;
    color: white;
}

.priority-low {
    background-color: #27ae60;
    color: white;
}

/* Status styling */
.status-draft {
    color: #95a5a6;
    font-style: italic;
}

.status-pending {
    color: #f39c12;
    font-weight: bold;
}

.status-approved {
    color: #27ae60;
    font-weight: bold;
}

.status-rejected {
    color: #e74c3c;
    font-weight: bold;
}

/* Signatures section */
.signatures-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 40px;
    margin-top: 30px;
}

.employee-signature, .manager-signature {
    text-align: left;
}

.employee-signature p, .manager-signature p {
    margin: 10px 0 5px 0;
    font-weight: 600;
    color: #2c3e50;
}

.signature-line {
    height: 2px;
    background-color: #bdc3c7;
    margin: 20px 0 10px 0;
    border-radius: 1px;
}

.date-line {
    font-size: 12px;
    color: #7f8c8d;
    margin-top: 15px !important;
}

/* Reason text special styling */
.reason-text {
    background-color: #f8f9fa;
    padding: 10px;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    min-height: 60px;
    display: block;
    margin-top: 5px;
}

/* Print media queries */
@media print {
    .leave-request-format {
        padding: 15mm;
        box-shadow: none;
    }
    
    .section-break {
        break-inside: avoid;
    }
    
    .signatures-grid {
        break-inside: avoid;
        margin-top: 20px;
    }
}

/* Responsive design */
@media screen and (max-width: 768px) {
    .leave-request-format {
        padding: 15px;
        margin: 10px;
    }
    
    .field-group {
        flex-direction: column;
    }
    
    .field-group .label {
        min-width: auto;
        margin-bottom: 5px;
    }
    
    .signatures-grid {
        grid-template-columns: 1fr;
        gap: 20px;
    }
}
